code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100vw;
  height: 100vh;
  overflow: hidden;
  background: #a0a0a0;
}

nav {
  position: fixed;
  top: 0;
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 1em;
}

nav div {
  display: flex;
  padding: 1em;
  gap: 10em;
}

nav div a {
  text-decoration: none;
  color: #000;
  font-family: "Neue Montreal";
}

.header {
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 2em;
}

.header .h1 {
  position: relative;
  font-family: "Carpenter";
  font-size: 32vw;
  color: #1a1a1a;
  line-height: 1.125;
}

.overlay {
  position: fixed;
  width: 100vw;
  height: 100vh;
  z-index: 2;
  display: flex;
}

.bar {
  width: 10vw;
  height: 105vh;
  background: #1a1a1a;
}

.counter {
  width: 100%;
  height: 100%;
  position: fixed;
  display: flex;
  justify-content: flex-end;
  align-items: flex-end;
  color: #bcbcc4;
  padding: 0.2em 0.4em;
  font-size: 20vw;
  font-family: "Carpenter";
  z-index: 10000;
}

.hero {
  position: relative;
  width: calc(100vw - 4em);
  height: 100%;
  margin: 0 auto;
  border-radius: 10px;
  border: 4px solid #1a1a1a;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
